@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-details">
        <span class="task-assignee">@Task.Assignee</span>
        <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">Save</button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(error))
    {
        <div class="form-error">@error</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        error = null;
        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column with header, task cards, and an inline add form *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => HandleMoveLeft(task)"
                      OnMoveRight="() => HandleMoveRight(task)" />
        }
    </div>

    @if (showAddForm)
    {
        <AddTaskForm OnSave="HandleAddTask" OnCancel="() => showAddForm = false" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(TaskItem Task, string Direction)> OnTaskMoved { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        movingTaskId = task.Id;
        try
        {
            await OnTaskMoved.InvokeAsync((task, "left"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        movingTaskId = task.Id;
        try
        {
            await OnTaskMoved.InvokeAsync((task, "right"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnTaskCreated.InvokeAsync(formData);
        showAddForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar TotalCount="allTasks.Count"
                   ToDoCount="todoBucket.Count"
                   InProgressCount="inProgressBucket.Count"
                   DoneCount="doneBucket.Count"
                   OverdueCount="overdueCount" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"Done\")" />
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered buckets (used for stats)
    private List<TaskItem> todoBucket = new();
    private List<TaskItem> inProgressBucket = new();
    private List<TaskItem> doneBucket = new();
    private int overdueCount;

    // Filtered buckets (used for display)
    private List<TaskItem> filteredToDo = new();
    private List<TaskItem> filteredInProgress = new();
    private List<TaskItem> filteredDone = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void RebuildBuckets()
    {
        todoBucket = allTasks.Where(t => t.Status == "To Do").ToList();
        inProgressBucket = allTasks.Where(t => t.Status == "In Progress").ToList();
        doneBucket = allTasks.Where(t => t.Status == "Done").ToList();
        overdueCount = allTasks.Count(t => t.DueDate < DateTime.Today);

        ApplySearchFilter();
    }

    private void ApplySearchFilter()
    {
        filteredToDo = FilterBySearch(todoBucket);
        filteredInProgress = FilterBySearch(inProgressBucket);
        filteredDone = FilterBySearch(doneBucket);
    }

    private List<TaskItem> FilterBySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
        ApplySearchFilter();
    }

    private async Task HandleTaskMoved((TaskItem Task, string Direction) args)
    {
        var currentIndex = Array.IndexOf(Statuses, args.Task.Status);
        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(args.Task.Id, newStatus);

            // Update local state
            var index = allTasks.FindIndex(t => t.Id == args.Task.Id);
            if (index >= 0)
            {
                allTasks[index] = args.Task with { Status = newStatus };
            }
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);

            // CreateTaskAsync may not return the correct status for the column, so ensure it matches
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }

            allTasks.Add(newTask);
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

