toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar TotalCount="allTasks.Count"
                   ToDoCount="todoBucket.Count"
                   InProgressCount="inProgressBucket.Count"
                   DoneCount="doneBucket.Count"
                   OverdueCount="overdueCount" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="args => HandleTaskCreated(args, \"Done\")" />
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered buckets (used for stats)
    private List<TaskItem> todoBucket = new();
    private List<TaskItem> inProgressBucket = new();
    private List<TaskItem> doneBucket = new();
    private int overdueCount;

    // Filtered buckets (used for display)
    private List<TaskItem> filteredToDo = new();
    private List<TaskItem> filteredInProgress = new();
    private List<TaskItem> filteredDone = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void RebuildBuckets()
    {
        todoBucket = allTasks.Where(t => t.Status == "To Do").ToList();
        inProgressBucket = allTasks.Where(t => t.Status == "In Progress").ToList();
        doneBucket = allTasks.Where(t => t.Status == "Done").ToList();
        overdueCount = allTasks.Count(t => t.DueDate < DateTime.Today);

        ApplySearchFilter();
    }

    private void ApplySearchFilter()
    {
        filteredToDo = FilterBySearch(todoBucket);
        filteredInProgress = FilterBySearch(inProgressBucket);
        filteredDone = FilterBySearch(doneBucket);
    }

    private List<TaskItem> FilterBySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
        ApplySearchFilter();
    }

    private async Task HandleTaskMoved((TaskItem Task, string Direction) args)
    {
        var currentIndex = Array.IndexOf(Statuses, args.Task.Status);
        var newIndex = args.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(args.Task.Id, newStatus);

            // Update local state
            var index = allTasks.FindIndex(t => t.Id == args.Task.Id);
            if (index >= 0)
            {
                allTasks[index] = args.Task with { Status = newStatus };
            }
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);

            // CreateTaskAsync may not return the correct status for the column, so ensure it matches
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }

            allTasks.Add(newTask);
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

